class InMemoryStore:
    """Thread-safe in-memory data store for development."""

    def __init__(self):
        self._lock = threading.RLock()
        self._users: Dict[str, dict] = {}
        self._tokens: Dict[str, dict] = {}  # token -> {user_id, expires_at}
        self._user_data: Dict[str, Dict[str, str]] = {}  # user_id -> {key: value}

        # Seed with sample data
        self._seed_data()

    def _seed_data(self):
        """Seed the store with sample users."""
        sample_users = [
            {"username": "admin", "email": "admin@example.com", "password": "admin123"},
            {"username": "alice", "email": "alice@example.com", "password": "alice123"},
            {"username": "bob", "email": "bob@example.com", "password": "bob123"},
        ]
        for user in sample_users:
            user_id = str(uuid.uuid4())
            password_hash = hashlib.sha256(user["password"].encode()).hexdigest()
            self._users[user_id] = {
                "user_id": user_id,
                "username": user["username"],
                "email": user["email"],
                "password_hash": password_hash,
                "created_at": datetime.utcnow().isoformat(),
                "metadata": {"role": "admin" if user["username"] == "admin" else "user"},
            }
            self._user_data[user_id] = {
                "preferences": json.dumps({"theme": "dark", "language": "en"}),
                "profile": json.dumps({"bio": f"Hello, I'm {user['username']}!"}),
                "settings": json.dumps({"notifications": True, "two_factor": False}),
            }

    def find_user_by_username(self, username: str) -> Optional[dict]:
        with self._lock:
            for user in self._users.values():
                if user["username"] == username:
                    return user.copy()
        return None

    def get_user(self, user_id: str) -> Optional[dict]:
        with self._lock:
            user = self._users.get(user_id)
            return user.copy() if user else None

    def create_user(self, username: str, email: str, password: str) -> Optional[str]:
        with self._lock:
            # Check for duplicate username/email
            for user in self._users.values():
                if user["username"] == username:
                    return None
                if user["email"] == email:
                    return None

            user_id = str(uuid.uuid4())
            password_hash = hashlib.sha256(password.encode()).hexdigest()
            self._users[user_id] = {
                "user_id": user_id,
                "username": username,
                "email": email,
                "password_hash": password_hash,
                "created_at": datetime.utcnow().isoformat(),
                "metadata": {"role": "user"},
            }
            self._user_data[user_id] = {}
            return user_id

    def list_users(self, page: int = 1, page_size: int = 10) -> tuple:
        with self._lock:
            all_users = list(self._users.values())
            total = len(all_users)
            start = (page - 1) * page_size
            end = start + page_size
            return [u.copy() for u in all_users[start:end]], total

    def search_users(self, query: str, page: int = 1, page_size: int = 10) -> tuple:
        with self._lock:
            matched = [
                u.copy() for u in self._users.values()
                if query.lower() in u["username"].lower() or query.lower() in u["email"].lower()
            ]
            total = len(matched)
            start = (page - 1) * page_size
            end = start + page_size
            return matched[start:end], total

    def create_token(self, user_id: str) -> str:
        with self._lock:
            token = str(uuid.uuid4()) + "-" + str(uuid.uuid4())
            self._tokens[token] = {
                "user_id": user_id,
                "expires_at": (datetime.utcnow() + timedelta(hours=24)).isoformat(),
            }
            return token

    def validate_token(self, token: str) -> Optional[dict]:
        with self._lock:
            token_data = self._tokens.get(token)
            if not token_data:
                return None
            if datetime.fromisoformat(token_data["expires_at"]) < datetime.utcnow():
                del self._tokens[token]
                return None
            user = self._users.get(token_data["user_id"])
            if not user:
                return None
            return {"user_id": user["user_id"], "username": user["username"]}

    def invalidate_token(self, token: str) -> bool:
        with self._lock:
            if token in self._tokens:
                del self._tokens[token]
                return True
            return False

    def get_user_data(self, user_id: str, data_key: str) -> Optional[str]:
        with self._lock:
            user_data = self._user_data.get(user_id, {})
            return user_data.get(data_key)

    def get_all_user_data(self, user_id: str) -> Dict[str, str]:
        with self._lock:
            return self._user_data.get(user_id, {}).copy()


